module mg_00925(input clk, input reset, input in, output p);
reg [2:0] r; 
  always @(posedge clk or posedge reset) begin 
  if(reset) 
  r <= 0; 
  else begin 
  if(r) 
  r <= r + 3'b1; 
  if(in) 
  r <= 1; 
  end 
  end 
  assign p = r == 2 || r == 3 || r == 4 || r == 5; 
 endmodule

