reg [31:0] Value; 
  always @(negedge Reset_n_i or posedge Clk_i) 
  begin 
  if (!Reset_n_i) 
  begin 
  Value <= 'd0; 
  end 
  else 
  begin 
  if (Preset_i) begin 
  Value <= PresetVal_i; 
  end else if (Enable_i) 
  begin 
  Value <= Value - 1'b1; 
  end 
  end 
  end 
  assign Zero_o = (Value == 0 ? 1'b1 : 1'b0); 
 endmodule

