    err_detected,
    err_fatal,
    output_data
);

  input ctl_clk;
  input [INPUT_DATA_WIDTH  - 1 : 0] input_data;
  output [OUTPUT_DATA_WIDTH - 1 : 0] output_data;
  output err_corrected;
  output err_detected;
  output err_fatal;

  wire [OUTPUT_DATA_WIDTH - 1 : 0] output_data;
  wire err_corrected;
  wire err_detected;
  wire err_fatal;

  generate
    if (INPUT_DATA_WIDTH == 40) begin
      ddr2_v10_1_0002_alt_ddrx_decoder_40 decoder_40_inst (
          .clock        (ctl_clk),
          .data         (input_data[INPUT_DATA_WIDTH-2 : 0]),
          .err_corrected(err_corrected),
          .err_detected (err_detected),
          .err_fatal    (err_fatal),
          .q            (output_data)
      );
    end else if (INPUT_DATA_WIDTH == 72) begin
      ddr2_v10_1_0002_alt_ddrx_decoder_72 decoder_72_inst (
          .clock        (ctl_clk),
          .data         (input_data),
          .err_corrected(err_corrected),
          .err_detected (err_detected),
          .err_fatal    (err_fatal),
          .q            (output_data)
      );
    end
  endgenerate

endmodule

