module rtlpp_00067 (
  ap_clk,
  ap_rst_n,
  in0_V_TVALID,
  in0_V_TREADY,
  in0_V_TDATA,
  weights_V_TVALID,
  weights_V_TREADY,
  weights_V_TDATA,
  out_V_TVALID,
  out_V_TREADY,
  out_V_TDATA
);

input wire ap_clk;
input wire ap_rst_n;
input wire in0_V_TVALID;
output wire in0_V_TREADY;
input wire [31 : 0] in0_V_TDATA;
input wire weights_V_TVALID;
output wire weights_V_TREADY;
input wire [287 : 0] weights_V_TDATA;
output wire out_V_TVALID;
input wire out_V_TREADY;
output wire [15 : 0] out_V_TDATA;

// Embed the logic of the MVAU_hls_4 module
reg [15:0] result;
reg result_valid;

always @(posedge ap_clk or negedge ap_rst_n) begin
  if (!ap_rst_n) begin
    result <= 16'd0;
    result_valid <= 1'b0;
  end else if (in0_V_TVALID && weights_V_TVALID) begin
    // Assuming a simplified multiply and accumulate unit
    // Placeholder for the actual computation logic
    result <= in0_V_TDATA[15:0] * weights_V_TDATA[15:0]; // Simplified multiplication, actual logic might differ
    result_valid <= 1'b1;
  end else if (out_V_TREADY) begin
    result_valid <= 1'b0;
  end
end

assign in0_V_TREADY = ~result_valid;
assign weights_V_TREADY = ~result_valid;
assign out_V_TVALID = result_valid;
assign out_V_TDATA = result;

endmodule

