module origen_144870 (
    input wire [4:0] A1ADDR,
    input wire [31:0] A1DATA,
    input wire A1EN,
    input wire CLK1,
    input wire [4:0] B1ADDR,
    output reg [31:0] B1DATA
);

reg [31:0] mem [0:31];

initial begin
    integer i;
    for (i = 0; i < 32; i = i + 1) begin
        mem[i] = 32'b0;
    end
end

always @(posedge CLK1) begin
    if (A1EN) begin
        mem[A1ADDR] <= A1DATA;
    end
    B1DATA <= mem[B1ADDR];
