    $setup(A1DATA, posedge CLK1, 2);
    $setup(A1EN, posedge CLK1, 2);
    $setup(B1ADDR, posedge CLK1, 2);
    $hold(posedge CLK1, A1ADDR, 1);
    $hold(posedge CLK1, A1DATA, 1);
    $hold(posedge CLK1, A1EN, 1);
    $hold(posedge CLK1, B1ADDR, 1);
    (CLK1 => B1DATA) = 3;
endspecify
