module rtlpp_06875 (
  input          clk, reset,
  output         clk2,
  input signed [7:0]   x_in,
  output signed [16:0] x_e, x_o, g0, g1,
  output signed [8:0]  y_out
);

  reg signed [7:0] x_odd, x_even, x_wait;
  reg  clk_div2;

  reg signed [16:0] m0, m1, m2, m3, r0, r1, r2, r3;
  reg signed [16:0] x33, x99, x107;
  reg signed [16:0] y;
  reg [0:0] state;

  parameter even = 0, odd = 1;

  always @(posedge clk or posedge reset) 
  begin : Multiplex
    if (reset)              
      state <= even;
    else
      case (state)
        even : begin
          x_even <= x_in; 
          x_odd  <= x_wait;
          clk_div2 <= 1;
          state <= odd;
        end
        odd : begin
          x_wait <= x_in;
          clk_div2 <= 0;
          state <= even;
        end
      endcase  
  end

  always @(x_odd or x_even) 
  begin : RAG
    x33  = (x_odd <<< 5) + x_odd;            
    x99  = (x33 <<< 1) + x33;                  
    x107 = x99 + (x_odd <<< 3);

    m0 = (x_even <<< 7) - (x_even <<< 2); 
    m1 = x107 <<< 1;                      
    m2 = (x_even <<< 6) - (x_even <<< 3) + x_even; 
    m3 = x33;                               
  end

  always @(negedge clk_div2) 
  begin : AddPolyphase
    r0 <=  r2 + m0;        
    r2 <=  m2;             

    r1 <=  -r3 + m1;       
