  reg [31:0] divisor; 
  reg divisor_loaded; 
  reg expired; 
  reg alarm; 
  reg ien; 
  always @(posedge clk) begin 
  if (divisor_loaded == 1) begin 
  counter <= divisor; 
  expired <= 0; 
  end else begin 
  if (counter == 32'h00000001) begin 
  counter <= divisor; 
  expired <= 1; 
  end else begin 
  counter <= counter - 1; 
  expired <= 0; 
