module autovcoder_100854 (
    busClk,
    usbClk,
    rstSyncToBusClk,
    rstSyncToUsbClk,
    fifoWEn,
    fifoFull,
    busAddress,
    busWriteEn,
    busStrobe_i,
    busFifoSelect,
    busDataIn,
    busDataOut,
    fifoDataIn
);
  //FIFO_DEPTH = ADDR_WIDTH^2
  parameter FIFO_DEPTH = 64;
  parameter ADDR_WIDTH = 6;

  input busClk;
  input usbClk;
  input rstSyncToBusClk;
  input rstSyncToUsbClk;
  input fifoWEn;
  output fifoFull;
  input [2:0] busAddress;
  input busWriteEn;
  input busStrobe_i;
  input busFifoSelect;
  input [7:0] busDataIn;
  output [7:0] busDataOut;
  input [7:0] fifoDataIn;

  wire busClk;
  wire usbClk;
  wire rstSyncToBusClk;
  wire rstSyncToUsbClk;
  wire fifoWEn;
  wire fifoFull;
  wire [2:0] busAddress;
  wire busWriteEn;
  wire busStrobe_i;
  wire busFifoSelect;
  wire [7:0] busDataIn;
  wire [7:0] busDataOut;
  wire [7:0] fifoDataIn;

  //internal wires and regs
  wire [7:0] dataFromFifoToBus;
  wire fifoREn;
  wire forceEmptySyncToBusClk;
  wire forceEmptySyncToUsbClk;
  wire [15:0] numElementsInFifo;
  wire fifoEmpty;  //not used

  fifoRTL_simlib #(8, FIFO_DEPTH, ADDR_WIDTH) u_fifo (
      .wrClk(usbClk),
      .rdClk(busClk),
      .rstSyncToWrClk(rstSyncToUsbClk),
      .rstSyncToRdClk(rstSyncToBusClk),
      .dataIn(fifoDataIn),
      .dataOut(dataFromFifoToBus),
      .fifoWEn(fifoWEn),
      .fifoREn(fifoREn),
