module autovcoder_005413 (
    input [15:0] a,
    input [15:0] b,
    input [5:0] alufn,
    output reg [15:0] out,
    output reg [0:0] z,
    output reg [0:0] v,
    output reg [0:0] n
);



  wire [16-1:0] M_adder_out;
  wire [ 1-1:0] M_adder_z;
  wire [ 1-1:0] M_adder_v;
  wire [ 1-1:0] M_adder_n;
  reg  [16-1:0] M_adder_a;
  reg  [16-1:0] M_adder_b;
  reg  [ 6-1:0] M_adder_alufn;
  adder_16_9 adder (
      .a(M_adder_a),
      .b(M_adder_b),
      .alufn(M_adder_alufn),
      .out(M_adder_out),
      .z(M_adder_z),
      .v(M_adder_v),
      .n(M_adder_n)
  );

  wire [16-1:0] M_boolean_out;
  reg  [16-1:0] M_boolean_a;
  reg  [16-1:0] M_boolean_b;
  reg  [ 6-1:0] M_boolean_alufn;
  boolean_16_10 boolean (
      .a(M_boolean_a),
      .b(M_boolean_b),
      .alufn(M_boolean_alufn),
      .out(M_boolean_out)
  );

  wire [16-1:0] M_shifter_out;
  reg  [16-1:0] M_shifter_a;
  reg  [16-1:0] M_shifter_b;
  reg  [ 6-1:0] M_shifter_alufn;
  shifter_16_11 shifter (
      .a(M_shifter_a),
      .b(M_shifter_b),
      .alufn(M_shifter_alufn),
      .out(M_shifter_out)
  );

  wire [16-1:0] M_comparator_out;
  reg  [ 1-1:0] M_comparator_z;
  reg  [ 1-1:0] M_comparator_v;
  reg  [ 1-1:0] M_comparator_n;
  reg  [ 6-1:0] M_comparator_alufn;
  compare_16_12 comparator (
      .z(M_comparator_z),
      .v(M_comparator_v),
      .n(M_comparator_n),
      .alufn(M_comparator_alufn),
      .out(M_comparator_out)
  );

  always @* begin
    M_adder_alufn = alufn;
    M_adder_a = a;
    M_adder_b = b;
    z = M_adder_z;
    v = M_adder_v;
    n = M_adder_n;
    M_comparator_alufn = alufn;
    M_comparator_z = M_adder_z;
    M_comparator_v = M_adder_v;
    M_comparator_n = M_adder_n;
    M_boolean_alufn = alufn;
    M_boolean_a = a;
    M_boolean_b = b;
    M_shifter_alufn = alufn;
    M_shifter_a = a;
    M_shifter_b = b[0+3-:4];

    case (alufn[4+1-:2])
      2'h0: begin
        out = M_adder_out;
      end
      2'h1: begin
        out = M_boolean_out;
        z   = 1'h0;
        v   = 1'h0;
        n   = 1'h0;
      end
      2'h2: begin
        out = M_shifter_out;
        z   = 1'h0;
        v   = 1'h0;
        n   = 1'h0;
      end
      2'h3: begin
        out = M_comparator_out;
      end
      default: begin
        out = 16'h0000;
      end
    endcase
  end
endmodule

