module autovcoder_073265 (
    input        CLOCK_50,     //	On Board 50 MHz
    // Your inputs and outputs here
    input  [3:0] KEY,
    input  [9:0] SW,
    // The ports below are for the VGA output.  Do not change.
    output       VGA_CLK,      //	VGA Clock
    output       VGA_HS,       //	VGA H_SYNC
    output       VGA_VS,       //	VGA V_SYNC
    output       VGA_BLANK_N,  //	VGA BLANK
    output       VGA_SYNC_N,   //	VGA SYNC
    output [9:0] VGA_R,        //	VGA Red[9:0]
    output [9:0] VGA_G,        //	VGA Green[9:0]
    output [9:0] VGA_B,        //	VGA Blue[9:0]
    output [6:0] HEX0,
    output [6:0] HEX1,
    output [6:0] HEX2,
    output [6:0] HEX3,
    output [6:0] HEX4
);

  wire resetn;
  wire reset_c;
  assign resetn = KEY[0];

  // Create the colour, x, y and writeEn wires that are inputs to the controller.
  wire [2:0] colour;
  wire [7:0] x;
  wire [6:0] y;
  wire writeEn;
  wire [4:0] counter_transfer;
  wire increment_transfer, ld_x_transfer, ld_y_transfer;

  // Create an Instance of a VGA controller - there can be only one!
  // Define the number of colours as well as the initial background
  // image file (.MIF) for the controller.
  vga_adapter VGA (
      .resetn(resetn),
      .clock(CLOCK_50),
      .colour(colour),
      .x(x),
      .y(y),
      .plot(writeEn),
      /* Signals for the DAC to drive the monitor. */
      .VGA_R(VGA_R),
      .VGA_G(VGA_G),
      .VGA_B(VGA_B),
      .VGA_HS(VGA_HS),
      .VGA_VS(VGA_VS),
      .VGA_BLANK(VGA_BLANK_N),
      .VGA_SYNC(VGA_SYNC_N),
      .VGA_CLK(VGA_CLK)
  );
  defparam VGA.RESOLUTION = "160x120"; defparam VGA.MONOCHROME = "FALSE";
      defparam VGA.BITS_PER_COLOUR_CHANNEL = 1; defparam VGA.BACKGROUND_IMAGE = "black.mif";

  // Put your code here. Your code should produce signals x,y,colour and writeEn/plot
  // for the VGA controller, in addition to any other functionality your design may require.

  // Instantiate datapath
  datapath d0 (
      .x_out(x),
      .y_out(y),
      .colour_out(colour),
      .counter(counter_transfer),
      .clk(CLOCK_50),
      .reset_n(~resetn),
      .coord_in(SW[6:0]),
      .colour_in(SW[9:7]),
      .increment_counter(increment_transfer),
      .reset_counter(reset_c),
      .ld_x(ld_x_transfer),
      .ld_y(ld_y_transfer)
  );

  // Instantiate FSM control
  control_FSM c0 (
      .plot(writeEn),
      .increment_counter(increment_transfer),
      .reset_counter(reset_c),
      .ld_x(ld_x_transfer),
      .ld_y(ld_y_transfer),
      .clk(CLOCK_50),
      .reset_n(~resetn),
      .next_val(~KEY[3]),
      .go(~KEY[1]),
      .counter_in(counter_transfer)
  );

  hex_display h0 (
      .IN (x[3:0]),
      .OUT(HEX0)
  );
  hex_display h1 (
      .IN (x[7:4]),
      .OUT(HEX1)
  );
  hex_display h2 (
      .IN (y[3:0]),
      .OUT(HEX2)
  );
  hex_display h3 (
      .IN ({1'b0, y[6:4]}),
      .OUT(HEX3)
  );
  hex_display h4 (
      .IN (counter_transfer),
      .OUT(HEX4)
  );
endmodule

