  output take_no_action_tracemem_a;
  input clk;
  input [1:0] ir_in;
  input [37:0] sr;
  input vs_udr;
  input vs_uir;

  reg enable_action_strobe;
  reg [1:0] ir;
  reg [37:0] jdo;
  reg jxuir;
  reg sync2_udr;
  reg sync2_uir;
  wire sync_udr;
  wire sync_uir;
  wire take_action_break_a;
  wire take_action_break_b;
  wire take_action_break_c;
  wire take_action_ocimem_a;
  wire take_action_ocimem_b;
