module rtlpp_10320 (
  input wire clk,
  input wire reset,
  input signed [word_size_in-1:0] X,
  output reg signed [word_size_out-1:0] Y
);

parameter word_size_in = 8;
parameter word_size_out = 20;

wire signed [word_size_in:0] x1;
wire signed [10:0] x3;
assign x1 = X;
assign x3 = +(x1<<1)+(x1<<0);

wire signed [9:0] x_1;
wire signed [9:0] x0;
