assign x_9 = +(x7 << 0) - (x1 << 4);
assign x77 = -(x3 << 0) + (x5 << 4);
assign x187 = -(x5 << 0) + (x3 << 6);
assign x253 = -(x3 << 0) + (x1 << 8);
assign x229 = +(x5 << 0) + (x7 << 5);
