assign Y_in = MAC_0;

task reset_reg;
  begin
    MAC_0 <= 0;
    MAC_1 <= 0;
    MAC_2 <= 0;
    MAC_3 <= 0;
    MAC_4 <= 0;
    MAC_5 <= 0;
    MAC_6 <= 0;
    MAC_7 <= 0;
    MAC_8 <= 0;
    MAC_9 <= 0;
    MAC_10 <= 0;
    MAC_11 <= 0;
    MAC_12 <= 0;
    MAC_13 <= 0;
    MAC_14 <= 0;
    MAC_15 <= 0;
    MAC_16 <= 0;
    MAC_17 <= 0;
    MAC_18 <= 0;
    MAC_19 <= 0;
    MAC_20 <= 0;
    Y <= 0;
  end
endtask

task init_reg;
  begin
    Y <= Y;
    MAC_0 <= MAC_0;
    MAC_1 <= MAC_1;
    MAC_2 <= MAC_2;
    MAC_3 <= MAC_3;
    MAC_4 <= MAC_4;
    MAC_5 <= MAC_5;
    MAC_6 <= MAC_6;
    MAC_7 <= MAC_7;
    MAC_8 <= MAC_8;
    MAC_9 <= MAC_9;
    MAC_10 <= MAC_10;
    MAC_11 <= MAC_11;
    MAC_12 <= MAC_12;
    MAC_13 <= MAC_13;
    MAC_14 <= MAC_14;
    MAC_15 <= MAC_15;
    MAC_16 <= MAC_16;
    MAC_17 <= MAC_17;
    MAC_18 <= MAC_18;
    MAC_19 <= MAC_19;
    MAC_20 <= MAC_20;
  end
endtask

endmodule

