module autovcoder_064409 (  //Output
    datasync_r,
    //Input
    datain,
    clk,
    areset
);

  /****************************** parameters ******************************/
  // synopsys template
  parameter WIDTH = 16;

  /****************************************** OUTPUTS **********************************/

  output [WIDTH-1:0] datasync_r;  //The output signal, synchronize to the new clock domain

  /******************************************  INPUTS **********************************/

  input [WIDTH-1:0] datain;  //The input signal to the synchronizer
  input clk;  //The clock to be synchronize to
  input areset;  //ASync RESET signal

  /************************************** Wire DECLARATIONS ****************************/

  //No wire in that design

  /*************************************** Reg DECLARATIONS ****************************/

  reg [WIDTH-1:0] sample_r;  //The first stage in synchronization
  reg [WIDTH-1:0] datasync_r;  //The second stage in synchronization

  /*************************************************************************************/
  /*
   ----areset-------+---------------------+
                    +                     +
                 +--o--+               +--o--+
                 +     +               +     +
   ----datain--->+ FF1 +---sample_r--->+ FF2 +---datasync_r--->
                 +     +               +     +
                 +--^--+               +--^--+
                    |                     | 
                    |                     |
                   clk                   clk     
                                                                                         */
  /*************************************************************************************/

  // First sample
  always @(posedge clk or negedge areset)
    if (~areset) sample_r <= {WIDTH{1'b0}};
    else sample_r <= datain;

  // Second sample   
  always @(posedge clk or negedge areset)
    if (~areset) datasync_r <= {WIDTH{1'b0}};
    else datasync_r <= sample_r;

endmodule

files.autovcoder_133933.v:
module autovcoder_133933 (  
    input clk,  
    input reset,  
    input [1:0] command_type, // 00: no command, 01: read, 10: write  
    output reg command_processed  
);  
    reg [1:0] current_state;  
    reg [1:0] next_state;  

    // State encoding  
    parameter IDLE = 2'b00, READ = 2'b01, WRITE = 2'b10;  

    // State transition  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            current_state <= IDLE;  
        else  
            current_state <= next_state;  
    end  

    // Next state logic  
    always @(*) begin  
        case (current_state)  
            IDLE: begin  
                if (command_type == 2'b01)  
                    next_state = READ;  
                else if (command_type == 2'b10)  
                    next_state = WRITE;  
                else  
                    next_state = IDLE;  
            end  
            READ: begin  
                next_state = IDLE;  
            end  
            WRITE: begin  
                next_state = IDLE;  
            end  
            default: next_state = IDLE;  
        endcase  
    end  

    // Output logic  
    always @(posedge clk) begin  
        if (current_state == READ || current_state == WRITE)  
            command_processed <= 1;  
        else  
            command_processed <= 0;  
    end  
endmodule

