module origen_053447 #(
    parameter PACKET_BITS = 97,
    parameter NUM_LEAF_BITS = 6,
    parameter NUM_PORT_BITS = 4
) (
    input wire clk,
    input wire reset,
    output reg [PACKET_BITS-1:0] dout_leaf_interface2bft,
    input wire [PACKET_BITS-1:0] din_leaf_bft2interface,
    input wire resend,
    output reg [PACKET_BITS-1:0] stream_out,
    output wire resend_out,
    input wire [PACKET_BITS-1:0] stream_in,
    output reg [PACKET_BITS-1:0] configure_out
);

    localparam INPUT_PORT_MAX_NUM = 8;
    localparam OUTPUT_PORT_MIN_NUM = 9;

    reg vldBit;
    reg [NUM_LEAF_BITS-1:0] leaf;
    reg [NUM_PORT_BITS-1:0] port;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            stream_out <= 0;
            configure_out <= 0;
            vldBit <= 0;
            leaf <= 0;
            port <= 0;
        end else begin
            vldBit <= din_leaf_bft2interface[PACKET_BITS-1];
            leaf <= din_leaf_bft2interface[PACKET_BITS-2 -: NUM_LEAF_BITS];
            port <= din_leaf_bft2interface[PACKET_BITS-2-NUM_LEAF_BITS -: NUM_PORT_BITS];

            if (port >= 2 && port <= INPUT_PORT_MAX_NUM) begin
                stream_out <= din_leaf_bft2interface;
            end else begin
                stream_out <= 0;
            end

            if (port == 0 || port == 1 || port >= OUTPUT_PORT_MIN_NUM) begin
                configure_out <= din_leaf_bft2interface;
            end else begin
                configure_out <= 0;
            end
        end
    end

    assign resend_out = resend;
    always @(*) begin
        dout_leaf_interface2bft = stream_in;
    end

endmodule

files.autovcoder_125938.v:
module autovcoder_125938 #(parameter NUM_USERS = 10, NUM_ITEMS = 10, LATENT_DIM = 5) (  
    input clk,  
    input rst,  
    input valid_input,  
    input [3:0] user_idx,  
    input [3:0] item_idx,  
    input [31:0] true_rating,  
    output reg [31:0] predicted_rating  
);  

    reg signed [31:0] user_factors [0:NUM_USERS-1][0:LATENT_DIM-1];  
    reg signed [31:0] item_factors [0:NUM_ITEMS-1][0:LATENT_DIM-1];  
    reg signed [31:0] learning_rate;  

    integer i;  

    initial begin  
        learning_rate = 32'h00000001; // Small learning rate  
        // Initialize user and item factors  
        for (i = 0; i < NUM_USERS; i = i + 1) begin  
            user_factors[i][0] = $urandom_range(0, 100);  
            user_factors[i][1] = $urandom_range(0, 100);  
            user_factors[i][2] = $urandom_range(0, 100);  
            user_factors[i][3] = $urandom_range(0, 100);  
            user_factors[i][4] = $urandom_range(0, 100);  
        end  
        for (i = 0; i < NUM_ITEMS; i = i + 1) begin  
            item_factors[i][0] = $urandom_range(0, 100);  
            item_factors[i][1] = $urandom_range(0, 100);  
            item_factors[i][2] = $urandom_range(0, 100);  
            item_factors[i][3] = $urandom_range(0, 100);  
            item_factors[i][4] = $urandom_range(0, 100);  
        end  
    end  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            predicted_rating <= 0;  
        end else if (valid_input) begin  
            // Predict the rating  
            predicted_rating <= 0;  
            for (i = 0; i < LATENT_DIM; i = i + 1) begin  
                predicted_rating <= predicted_rating + user_factors[user_idx][i] * item_factors[item_idx][i];  
            end  

            // Update the factors using gradient descent  
            for (i = 0; i < LATENT_DIM; i = i + 1) begin  
                user_factors[user_idx][i] <= user_factors[user_idx][i] + learning_rate * (true_rating - predicted_rating) * item_factors[item_idx][i];  
                item_factors[item_idx][i] <= item_factors[item_idx][i] + learning_rate * (true_rating - predicted_rating) * user_factors[user_idx][i];  
            end  
        end  
    end  
endmodule

files.origen_074788.v:
module origen_074788 #(
    parameter DATA_LENGTH = 32,
    parameter WORD_SIZE = 8
)(
    input wire data_in,
    input wire clock,
    input wire reset,
    input wire start,
    output reg [WORD_SIZE-1:0] data_out,
    output wire RCO,
    output wire busy
);

    localparam START_BIT = 1'b1;
    localparam COUNTER_SIZE = $clog2(WORD_SIZE);
    localparam DATA_COUNTER_SIZE = $clog2(DATA_LENGTH);

    reg [WORD_SIZE-1:0] data;
    reg [COUNTER_SIZE-1:0] counter;
    reg [DATA_COUNTER_SIZE-1:0] data_counter;
    reg [3:0] ps, ns;

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            ps <= 4'b0000;
            data <= 8'hC9;
            counter <= 0;
            data_counter <= 0;
        end else begin
            ps <= ns;
            if (ps == 4'b0010) begin
                data <= {data[WORD_SIZE-2:0], data_in};
                counter <= (counter == WORD_SIZE - 1) ? 0 : counter + 1;
                data_counter <= data_counter + 1;
            end
        end
    end

    always @(*) begin
        case (ps)
            4'b0000: ns = start ? 4'b0001 : 4'b0000;
            4'b0001: ns = (data_in == START_BIT) ? 4'b0010 : 4'b0001;
            4'b0010: ns = (data_counter == DATA_LENGTH - 1) ? 4'b0000 : 4'b0010;
            default: ns = 4'b0000;
        endcase
    end

    assign RCO = (counter == WORD_SIZE - 1);
    assign busy = (ps != 4'b0000) || start;

    always @(posedge clock) begin
        if (RCO) data_out <= data;
    end

endmodule

