module autovcoder_074483 #(
    parameter DELAY        = 1,
    parameter WIDTH        = 32,
    parameter SUBFRAME_LSB = 11,
    parameter SUBFRAME_MSB = 19
) (
    input              clk,
    input              reset,
    output [WIDTH-1:0] counter
);

  localparam S_COUNT = 3'b001;
  localparam S_WAIT1 = 3'b010;
  localparam S_WAIT2 = 3'b100;

  localparam fb = WIDTH - SUBFRAME_MSB - 1;
  localparam sb = SUBFRAME_MSB - SUBFRAME_LSB + 1;
  localparam cb = SUBFRAME_MSB + 1;

  localparam fh = WIDTH - 1;
  localparam fl = SUBFRAME_MSB + 1;
  localparam sh = SUBFRAME_MSB;
  localparam sl = SUBFRAME_LSB;

  // Wrap counter one subframe early.
  // Compare counter to {subframe, other} == {11...10, 11...1}.
  localparam skip_subframe = {cb{1'b1}} & ~(1 << sl);

  reg [fh:fl] frame_r;
  reg [ sh:0] counter_r;
  reg [  2:0] state;

  assign counter = {frame_r, counter_r};

  always @(posedge clk)
    if (reset) begin
      frame_r <= 0;
      counter_r <= 0;
      state <= S_COUNT;
    end else
      case (state)

        S_COUNT: begin
          counter_r <= counter_r + 1;
          if (counter_r[5:0] == 63) begin
            state <= S_WAIT1;
          end
          if (counter_r == skip_subframe) begin
            counter_r <= 0;
            frame_r   <= frame_r + 1;
          end
        end

        S_WAIT1: state <= S_WAIT2;

        S_WAIT2: state <= S_COUNT;

      endcase

endmodule

files.origen_007315.v:
module origen_007315(
    input wire clk,
    input wire [15:0] A,
    input wire [15:0] B,
    input wire [2:0] select,
    output reg z_flag,
    output reg [15:0] out,
    output reg finish
);

    always @(*) begin
        case(select)
            3'b000: begin // Addition
                out = A + B;
                z_flag = (out == 16'b0);
                finish = 1'b0;
            end
            3'b001: begin // Subtraction
                out = A - B;
                z_flag = (out == 16'b0);
                finish = 1'b0;
            end
            3'b010: begin // Multiplication
                out = A * B;
                finish = 1'b0;
            end
            3'b011: begin // Pass-through A
                out = A;
                finish = 1'b0;
            end
            3'b100: begin // Pass-through B
                out = B;
                finish = 1'b0;
            end
            3'b101: begin // Zero
                out = 16'b0;
                finish = 1'b0;
            end
            3'b110: begin // Finish
                out = 16'b0;
                finish = 1'b1;
            end
            default: begin
                out = 16'b0;
                finish = 1'b0;
            end
        endcase
    end

endmodule

