module origen_075490 #(
    parameter precision_loss_width = 8,
    parameter input_freezed = 0
) (
    input wire clk,
    input wire RSTM,
    input wire CEM,
    input wire MREG,
    input wire [89:0] M_temp,
    input wire [precision_loss_width-1:0] result_SIMD_carry,
