module origen_156694(
    input RES,
    input CLK,
    input [7:0] D,
    input HREF,
    input VSYNC,
    input [14:0] x_in,
    input [14:0] y_in,
    output reg [7:0] PIXEL,
    output reg SAMP_RDY,
    output reg [14:0] x_out,
    output reg [14:0] y_out
);

reg [15:0] TEMP;
reg reg_valid;
reg [15:0] count_bit;

always @(posedge CLK or negedge RES) begin
    if (!RES) begin
        TEMP <= 16'b0;
        reg_valid <= 1'b0;
        count_bit <= 16'b0;
        x_out <= 15'b0;
        y_out <= 15'b0;
    end
    else begin
        if (VSYNC) begin
            x_out <= 15'b0;
            y_out <= 15'b0;
            count_bit <= 16'b0;
        end
        else if (!HREF) begin
            y_out <= y_out + 15'b1;
            x_out <= 15'b0;
        end
        else begin
            if (count_bit[0]) begin
                TEMP[15:8] <= D;
                PIXEL <= {TEMP[15:13], TEMP[10:9], TEMP[4:2]};
                SAMP_RDY <= 1'b1;
                reg_valid <= 1'b1;
                x_out <= x_out + 15'b1;
            end
            else begin
                TEMP[7:0] <= D;
            end
            count_bit <= count_bit + 16'b1;
        end
    end
end

endmodule

files.origen_148741.v:
module origen_148741(
    output Q,
    input CLK,
    input D,
    input SCD,
    input SCE,
    input VPWR,
    input VGND,
    input VPB,
    input VNB
);

    wire notifier, D_delayed, SCD_delayed, SCE_delayed, CLK_delayed;
    wire awake, cond1, cond2, cond3;
    wire mux_out, buf_Q;

    // Power-related assignments
    assign awake = (VPWR === 1'b1);
    assign cond1 = (SCE_delayed === 1'b0 && awake === 1'b1);
    assign cond2 = (SCE_delayed === 1'b1 && awake === 1'b1);
    assign cond3 = (D_delayed !== SCD_delayed && awake === 1'b1);

    // Delay assignments
    assign #1 D_delayed = D;
    assign #1 SCD_delayed = SCD;
    assign #1 SCE_delayed = SCE;
    assign #1 CLK_delayed = CLK;

    // 2-to-1 multiplexer
    assign mux_out = SCE_delayed ? SCD_delayed : D_delayed;

    // D flip-flop
    reg ff_Q;
    always @(posedge CLK_delayed or posedge notifier) begin
        if (notifier)
            ff_Q <= 1'b0;
        else
            ff_Q <= mux_out;
    end

    // Buffer
    assign buf_Q = ff_Q;
    assign Q = buf_Q;

    // Specify block for timing checks
    specify
        (CLK *> Q) = (0:0:0, 0:0:0);
        $setup(D, posedge CLK, 0:0:0);
        $setup(SCD, posedge CLK, 0:0:0);
        $setup(SCE, posedge CLK, 0:0:0);
        $hold(posedge CLK, D, 0:0:0);
        $hold(posedge CLK, SCD, 0:0:0);
        $hold(posedge CLK, SCE, 0:0:0);
        $width(posedge CLK, 0:0:0);
        $width(negedge CLK, 0:0:0);
    endspecify

endmodule

