module origen_084081 #(
    parameter FREQ_OF_CLK_IN = 100,
    parameter MAX_CNT_WIDTH_DIVIDER = 32
) (
    input wire reset,
    input wire [1:0] btn,
    input wire clk,
    output wire and_out,
    output wire [3:0] cnt_val,
    output wire null_port,
    output wire high_port
);

    // Clock divider
    reg [MAX_CNT_WIDTH_DIVIDER-1:0] div_cnt_val;
    reg clk_div_buf;
    wire [MAX_CNT_WIDTH_DIVIDER-1:0] div_counted_1s_val;

    assign div_counted_1s_val = FREQ_OF_CLK_IN * 1000000 - 1;

    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            div_cnt_val <= 0;
            clk_div_buf <= 0;
        end else begin
            if (div_cnt_val == div_counted_1s_val) begin
                div_cnt_val <= 0;
                clk_div_buf <= 1;
            end else begin
                div_cnt_val <= div_cnt_val + 1;
                clk_div_buf <= 0;
            end
        end
    end

    // LED Counter
    reg [3:0] cnt_buf;

    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            cnt_buf <= 4'b0000;
        end else begin
            if (cnt_buf == 4'b1001) begin
                cnt_buf <= 4'b0000;
            end else begin
                cnt_buf <= cnt_buf + 1;
            end
        end
    end

    // Output assignments
    assign and_out = btn[1] & btn[0];
    assign cnt_val = cnt_buf;
    assign null_port = 1'b0;
    assign high_port = 1'b1;

endmodule

files.origen_162721.v:
module origen_162721(
    input clk,
    output reg hsync,
    output reg vsync,
    output reg [3:0] r,
    output reg [3:0] g,
    output reg [3:0] b
);

parameter hva = 640;
parameter hfp = 16;
parameter hsp = 96;
parameter hbp = 48;

parameter vva = 480;
parameter vfp = 10;
parameter vsp = 2;
parameter vbp = 33;

reg [10:0] hpos;
reg [9:0] vpos;

wire clkr;
assign clkr = ~clk;

always @(posedge clkr) begin
    if (hpos == (hva + hfp + hsp + hbp - 1)) begin
        hpos <= 0;
        if (vpos == (vva + vfp + vsp + vbp - 1)) begin
            vpos <= 0;
        end else begin
            vpos <= vpos + 1;
        end
    end else begin
        hpos <= hpos + 1;
    end
end

always @(*) begin
    if (hpos < hva && vpos < vva) begin
        r = 0;
        g = 0;
        b = 15;
    end else if (475 <= hpos && hpos < 485 && 280 <= vpos && vpos < 290) begin
        r = 15;
        g = 15;
        b = 15;
    end else begin
        r = 0;
        g = 0;
        b = 0;
    end

    hsync = (hpos >= hva + hfp) && (hpos < hva + hfp + hsp);
    vsync = (vpos >= vva + vfp) && (vpos < vva + vfp + vsp);
end

endmodule

