module rtlpp_09156
(
    input        clk,           
    input        clk7_en,
    input        clk7n_en,
    input        aen,           
    input        rd,            
    input        wr,            
    input        reset,         
    input  [3:0] rs,            
    input  [7:0] data_in,       
    output [7:0] data_out,      
    input        tick,          
    input        eclk,          
    output       irq,           
    input  [7:2] porta_in,      
    output [3:0] porta_out,     
    input  [7:0] portb_in,      

    input        kms_level,
    input  [1:0] kbd_mouse_type,
    input  [7:0] kbd_mouse_data,
    output       freeze,        
    input        hrtmon_en
);

wire [7:0] icr_out;
wire [7:0] tmra_out;
wire [7:0] tmrb_out;
wire [7:0] tmrd_out;
wire [7:0] sdr_out;
reg  [7:0] pa_out;
reg  [7:0] pb_out;
wire [7:0] portb_out;
wire       alrm;        
wire       ta;          
wire       tb;          
wire       tmra_ovf;      

wire       spmode;        
wire       ser_tx_irq;      
reg  [3:0] ser_tx_cnt;   
reg        ser_tx_run;      

reg        tick_del;      

wire  pra, prb, ddra, ddrb, cra, talo, tahi, crb, tblo, tbhi, tdlo, tdme, tdhi, icrs, sdr;
wire  enable;

assign enable = aen & (rd | wr);

assign  pra  = enable && rs==4'h0;
assign  prb  = enable && rs==4'h1;
assign  ddra = enable && rs==4'h2;
assign  ddrb = enable && rs==4'h3;
assign  talo = enable && rs==4'h4;
assign  tahi = enable && rs==4'h5;
assign  tblo = enable && rs==4'h6;
assign  tbhi = enable && rs==4'h7;
