    output [31:0] bus_A,
    input [31:0] bus_in,
    output [31:0] bus_out,
    output bus_WE,
    bus_RE,
    output [7:0] current_opcode
);
  reg  [5:1] full;
  wire [4:0] ue = {full[4:1], full[5]};
  always @(posedge clk) begin
    if (rst) full <= 'b010000;
    else full <= {ue[4], ue[3], ue[2], ue[1], ue[0]};
  end
