    end
  reg [31:0] MAR, MDRw, C;
  wire [31:0] ALU_op2 = (memory ? displacement : (sub ? (~B) : B));
  wire [31:0] ALUout = ((A + ALU_op2) + sub);
  always @(posedge clk)
    if (rst) ZF = 0;
    else if (ue[2]) begin
      MAR <= ALUout;
      C <= (move ? B : ALUout);
      MDRw <= B;
      if (aluop) ZF <= (ALUout == 0);
    end
  reg [31:0] MDRr;
  always @(posedge clk) if ((ue[3] && load)) MDRr <= bus_in;
  assign bus_A  = (ue[3] ? MAR : (ue[0] ? IP : 0));
  assign bus_RE = (ue[0] || (ue[3] && load));
  reg [31:0] R[7:0];
  assign Aop = R[Aad];
  assign Bop = R[Bad];
  assign bus_WE = (ue[3] && store);
  assign bus_out = MDRw;
  always @(posedge clk)
    if (rst) begin
      R[0] <= 0;
      R[1] <= 0;
      R[2] <= 0;
      R[3] <= 0;
      R[4] <= 0;
      R[5] <= 0;
      R[6] <= 0;
      R[7] <= 0;
    end else if (ue[4])
      if (((aluop || move) || load))
        if (load) R[RS] <= '0;
        else R[RD] <= C;
  assign current_opcode = opcode;
endmodule

