module autovcoder_085641 (
    // inputs:
    clk,
    rd,
    reset_n,
    wr,
    wr_data,

    // outputs:
    almost_empty,
    almost_full,
    empty,
    full,
    rd_data
);

  output almost_empty;
  output almost_full;
  output empty;
  output full;
  output [40:0] rd_data;
  input clk;
  input rd;
  input reset_n;
  input wr;
  input [40:0] wr_data;


  wire        almost_empty;
  wire        almost_full;
  wire        empty;
  reg  [ 1:0] entries;
  reg  [40:0] entry_0;
  reg  [40:0] entry_1;
  wire        full;
  reg         rd_address;
  reg  [40:0] rd_data;
  wire [ 1:0] rdwr;
  reg         wr_address;
  assign rdwr = {rd, wr};
  assign full = entries == 2;
  assign almost_full = entries >= 1;
  assign empty = entries == 0;
  assign almost_empty = entries <= 1;
  always @(entry_0 or entry_1 or rd_address) begin
    case (rd_address)  // synthesis parallel_case full_case

      1'd0: begin
        rd_data = entry_0;
      end  // 1'd0 

      1'd1: begin
        rd_data = entry_1;
      end  // 1'd1 

      default: begin
      end  // default

    endcase  // rd_address
  end


  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0) begin
      wr_address <= 0;
      rd_address <= 0;
      entries <= 0;
    end else
      case (rdwr)  // synthesis parallel_case full_case

        2'd1: begin
          // Write data
          if (!full) begin
            entries <= entries + 1;
            wr_address <= (wr_address == 1) ? 0 : (wr_address + 1);
          end
        end  // 2'd1 

        2'd2: begin
          // Read data
          if (!empty) begin
            entries <= entries - 1;
            rd_address <= (rd_address == 1) ? 0 : (rd_address + 1);
          end
        end  // 2'd2 

        2'd3: begin
          wr_address <= (wr_address == 1) ? 0 : (wr_address + 1);
          rd_address <= (rd_address == 1) ? 0 : (rd_address + 1);
        end  // 2'd3 

        default: begin
        end  // default

      endcase  // rdwr
  end


  always @(posedge clk) begin
    //Write data
    if (wr & !full)
      case (wr_address)  // synthesis parallel_case full_case

        1'd0: begin
          entry_0 <= wr_data;
        end  // 1'd0 

        1'd1: begin
          entry_1 <= wr_data;
        end  // 1'd1 

        default: begin
        end  // default

      endcase  // wr_address
  end



endmodule

files.autovcoder_022931.v:
module autovcoder_022931 (
    input CLK,

    input [31:0] din,
    input wr_en,
    input [3:0] wr_addr,
    input wr_seq,

    // ==============================================================
    //
    //   OUTPUT OPERATION
    //
    // 1. At some stage, 'core_out_ready' asserts.
    //    core_out_ctx_num, core_out_seq_num are set accordingly.
    // 2. Wait for input rd_en, then transmit 16 x 16-bit
    //
    // ==============================================================
    output reg [15:0] dout,
    output reg core_out_ready = 0,
    core_out_start = 0,
    output reg core_out_ctx_num,
    core_out_seq_num,
    input rd_en
);

  (* RAM_STYLE="BLOCK" *)
  reg [31:0] mem[31:0];

  reg full0 = 0, full1 = 0;
  wire rst_full0, rst_full1;
  reg seq0, seq1;
  reg [15:0] X_INPUT_ERRORS = 0;


  // *****************************************************
  //
  // Input
  //
  // *****************************************************
  always @(posedge CLK) begin
    if (wr_en) mem[wr_addr] <= din;

    if (wr_en & wr_addr == 0) begin
      full0 <= 1;
      seq0  <= wr_seq;
    end
    if (rst_full0) full0 <= 0;

    if (wr_en & wr_addr == 8) begin
      full1 <= 1;
      seq1  <= wr_seq;
    end
    if (rst_full1) full1 <= 0;

`ifdef SIMULATION
    // Output has enough bandwith, there should be no errors
    if (wr_en & wr_addr == 0 & full0 | wr_en & wr_addr == 8 & full1)
      X_INPUT_ERRORS <= X_INPUT_ERRORS + 1'b1;
`endif
  end


  // *****************************************************
  //
  // Output
  //
  // *****************************************************
  reg [ 3:0] output_cnt = 0;  // output are 16 words X 16 bit

  reg [31:0] mem_r;

  localparam STATE_OUTPUT_NONE = 0,
					STATE_OUTPUT_READY = 1,
					STATE_OUTPUT_START = 2,
					STATE_OUTPUT_READ_MEM = 3;

  (* FSM_EXTRACT="true", FSM_ENCODING="one-hot" *)
  reg [1:0] state_output = STATE_OUTPUT_NONE;

  always @(posedge CLK) begin

    case (state_output)
      STATE_OUTPUT_NONE:
      if (full0 | full1) begin
        core_out_ready <= 1;
        core_out_ctx_num <= full0 ? 1'b0 : 1'b1;
        core_out_seq_num <= full0 ? seq0 : seq1;
        state_output <= STATE_OUTPUT_READY;
      end

      STATE_OUTPUT_READY:
      if (rd_en) begin
        state_output <= STATE_OUTPUT_START;
      end

      STATE_OUTPUT_START: begin
        core_out_ready <= 0;
        state_output   <= STATE_OUTPUT_READ_MEM;
      end

      STATE_OUTPUT_READ_MEM: begin
        core_out_start <= output_cnt == 0;
        mem_r <= mem[{core_out_ctx_num, output_cnt[3:1]}];

        output_cnt <= output_cnt + 1'b1;
        if (output_cnt == 15) state_output <= STATE_OUTPUT_NONE;
      end
    endcase
  end

  reg dout_en = 0;

  always @(posedge CLK) begin
    dout_en <= state_output == STATE_OUTPUT_READ_MEM;
    if (dout_en) dout <= output_cnt[0] ? mem_r[31:16] : mem_r[15:0];
  end

  assign rst_full0 = ~core_out_ctx_num & state_output == STATE_OUTPUT_START;
  assign rst_full1 = core_out_ctx_num & state_output == STATE_OUTPUT_START;


endmodule

files.autovcoder_005001.v:
module autovcoder_005001 (
    clk,
    reset_n,

    // sink
    in_data_0,
    in_valid_0,
    in_ready_0,
    in_startofpacket_0,
    in_endofpacket_0,
    in_empty_0,
    in_error_0,

    // sink
    in_data_1,
    in_valid_1,
    in_ready_1,
    in_startofpacket_1,
    in_endofpacket_1,
    in_empty_1,
    in_error_1,

    // source
    out_data,
    out_valid,
    out_ready,
    out_startofpacket,
    out_endofpacket,
    out_empty,
    out_error,

    // in control
    control_address,
    control_write,
    control_read,
    control_readdata,
    control_writedata

);


  // ---------------------------------------------------------------------
  // Parameters
  // ---------------------------------------------------------------------
  parameter SYMBOLS_PER_BEAT = 4;
  parameter BITS_PER_SYMBOL = 8;
  parameter ERROR_WIDTH = 1;
  parameter USE_PACKETS = 1;
  parameter EMPTY_WIDTH = 0;
  parameter MAX_CHANNELS = 2;

  localparam DATA_WIDTH = SYMBOLS_PER_BEAT * BITS_PER_SYMBOL;

  // ---------------------------------------------------------------------
  // Input/Output Signals
  // ---------------------------------------------------------------------
  input clk;
  input reset_n;

  input [DATA_WIDTH - 1 : 0] in_data_0;
  input in_valid_0;
  input in_startofpacket_0;
  input in_endofpacket_0;
  input [EMPTY_WIDTH - 1 : 0] in_empty_0;
  input [ERROR_WIDTH - 1 : 0] in_error_0;
  output in_ready_0;

  input [DATA_WIDTH - 1 : 0] in_data_1;
  input in_valid_1;
  input in_startofpacket_1;
  input in_endofpacket_1;
  input [EMPTY_WIDTH - 1 : 0] in_empty_1;
  input [ERROR_WIDTH - 1 : 0] in_error_1;
  output in_ready_1;

  output [DATA_WIDTH - 1 : 0] out_data;
  output out_valid;
  output out_startofpacket;
  output out_endofpacket;
  output [EMPTY_WIDTH - 1 : 0] out_empty;
  output [ERROR_WIDTH - 1 : 0] out_error;
  input out_ready;

  input control_address;
  input control_read;
  input control_write;
  input [31 : 0] control_writedata;
  output reg [31 : 0] control_readdata;

  reg selector;

  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      control_readdata <= 0;
      selector <= 0;
    end else begin
      if (control_write) begin
        selector <= 0;
        selector <= control_writedata;
      end else if (control_read) begin
        control_readdata <= 0;
        control_readdata <= selector;
      end
    end
  end

  assign out_data          = selector == 1'b0 ? in_data_0 : in_data_1;
  assign out_valid         = selector == 1'b0 ? in_valid_0 : in_valid_1;
  assign out_startofpacket = selector == 1'b0 ? in_startofpacket_0 : in_startofpacket_1;
  assign out_endofpacket   = selector == 1'b0 ? in_endofpacket_0 : in_endofpacket_1;
  assign out_empty         = selector == 1'b0 ? in_empty_0 : in_empty_1;
  assign out_error         = selector == 1'b0 ? in_error_0 : in_error_1;
  assign in_ready_0        = selector == 1'b0 ? out_ready : 1'b0;
  assign in_ready_1        = selector == 1'b1 ? out_ready : 1'b0;

endmodule

