module autovcoder_022408 (
    clk,
    rst,
    addr_rd,
    we_rd,
    din,
    addr_wr,
    we_wr,
    dout
);

  input clk, rst;

  input din;
  output wire [11:0] addr_rd, addr_wr;
  output wire we_rd, we_wr;
  output reg dout;

  /* States. At RD0, we read 0. At CK0 we check 0 and read 1. ...
 * At CK7, we read the X position to see if the current cell is filled.
 * At WR, we write the next state according to neighbor count N. 
 * When all 4096 cells are filled, we go into STOP and wait there.
 * [0][1][2]
 * [3][x][4]
 * [5][6][7] */
  parameter RD0 = 0;
  parameter CK0 = 1;
  parameter CK1 = 2;
  parameter CK2 = 3;
  parameter CK3 = 4;
  parameter CK4 = 5;
  parameter CK5 = 6;
  parameter CK6 = 7;
  parameter CK7 = 8;
  parameter WR = 9;
  parameter DONE = 10;
  reg [3:0] state;
  initial state = RD0;

  /* The current cell. Using rdX and rdY enables us to implement
 * side wrapping just by the means of overflow and get away
 * with 6-bit adders in the process. N is neighbor count. */
  reg [11:0] ptr;
  reg [5:0] rdX, rdY;
  reg [2:0] N;

  /* Use many always blocks to show different sequential and
 * combinatorial components. This is a state machine with output
 * given only at the WR state. Until that time, it checks the neighbor
 * cells and keeps a counter N. When WR is reached, a combinational
 * logic stage decides whether to write 0 or 1 to the next state of game. */
  always @(posedge clk) begin
    if (rst) begin
      ptr   <= 0;
      state <= RD0;
    end else if (state == RD0) state <= CK0;
    else if (state == CK0) state <= CK1;
    else if (state == CK1) state <= CK2;
    else if (state == CK2) state <= CK3;
    else if (state == CK3) state <= CK4;
    else if (state == CK4) state <= CK5;
    else if (state == CK5) state <= CK6;
    else if (state == CK6) state <= CK7;
    else if (state == CK7) state <= WR;
    else if (state == WR) begin
      ptr <= ptr + 1;
      if (ptr == 4095) state <= DONE;
      else state <= RD0;
    end else begin
      ptr   <= 12'bx;
      state <= 4'bx;
    end
  end

  always @(posedge clk) begin
    if (rst) N <= 0;
    else if (state != RD0 && state != WR && state != DONE) begin
      if (din) N <= N + 1;
    end else N <= 0;
  end

  always @(state) begin
    if (state == RD0) begin
      rdX = ptr[5:0] - 1;
      rdY = ptr[11:6] - 1;
    end else if (state == CK0) begin
      rdX = ptr[5:0];
      rdY = ptr[11:6] - 1;
    end else if (state == CK1) begin
      rdX = ptr[5:0] + 1;
      rdY = ptr[11:6] - 1;
    end else if (state == CK2) begin
      rdX = ptr[5:0] - 1;
      rdY = ptr[11:6];
    end else if (state == CK3) begin
      rdX = ptr[5:0] + 1;
      rdY = ptr[11:6];
    end else if (state == CK4) begin
      rdX = ptr[5:0] - 1;
      rdY = ptr[11:6] + 1;
    end else if (state == CK5) begin
      rdX = ptr[5:0];
      rdY = ptr[11:6] + 1;
    end else if (state == CK6) begin
      rdX = ptr[5:0] + 1;
      rdY = ptr[11:6] + 1;
    end else if (state == CK7) begin
      rdX = ptr[5:0];
      rdY = ptr[11:6];
    end else begin
      rdX = 6'bx;
      rdY = 6'bx;
    end
  end

  always @(state) begin
    if (N == 3) dout = 1;
    else if (N == 2 && din == 1) dout = 1;
    else dout = 0;
  end

  /* what to actually send to the RAM */
  assign addr_rd = {rdY, rdX};
  assign addr_wr = ptr;
  assign we_rd   = 0;  /* duh */
  assign we_wr   = (state == WR);

endmodule

files.autovcoder_086351.v:
module autovcoder_086351 (
    input CLK,
    output [47:0] INSTR,
    input [2:0] ISIZE,
    input IFETCH,
    input FLUSH,
    input MREQ,
    input WR,
    input WORD,
    input [20:0] ADDR,
    input [20:0] IADDR,
    output reg CE186,  // CPU clock enable
    input [31:0] RAM_DIN,
    output [31:0] RAM_DOUT,
    output [18:0] RAM_ADDR,
    output RAM_MREQ,
    output wire [3:0] RAM_WMASK,
    output reg [15:0] DOUT,
    input [15:0] DIN,
    input CE,  // BIU clock enable
    output reg data_bound,
    input [1:0] WSEL,  // normally {~ADDR[0], ADDR[0]}
    output reg RAM_RD,
    output reg RAM_WR
);

  reg [31:0] queue[3:0];
  reg [1:0] STATE = 0;
  reg OLDSTATE = 1;
  reg [3:0] qpos = 0;
  reg [4:0] qsize = 0;
  reg [1:0] rpos = 0;
  reg [18:0] piaddr = 0;
  reg [7:0] exdata = 0;
  reg rdi = 0;

  reg [1:0] NEXTSTATE;
  reg sflush;
  wire [4:0] newqsize = sflush ? -IADDR[1:0] : CE186 && IFETCH && ~FLUSH ? qsize - ISIZE : qsize;
  wire qnofull = qsize < 13;
  reg iread;  // = (qnofull && !RAM_RD && !RAM_WR) || sflush;
  wire [3:0] nqpos = (FLUSH && IFETCH) ? {2'b00, IADDR[1:0]} : (qpos + ISIZE);
  wire [18:0] MIADDR = sflush ? IADDR[20:2] : piaddr;
  wire split = (&ADDR[1:0]) && WORD;  // data between dwords
  wire [15:0] DSWAP = {
    WSEL[1] ? DIN[15:8] : DIN[7:0], WSEL[0] ? DIN[15:8] : DIN[7:0]
  };  //ADDR[0] ? {DIN[7:0], DIN[15:8]} : DIN;
  wire [1:0] a1 = nqpos[3:2] + 1;
  wire [1:0] a2 = nqpos[3:2] + 2;
  wire [31:0] q1 = rdi && (a1 == rpos) ? RAM_DIN : queue[a1];
  wire [7:0] q2 = rdi && (a2 == rpos) ? RAM_DIN[7:0] : queue[a2][7:0];

  assign INSTR = {q2, q1, queue[nqpos[3:2]]} >> {nqpos[1:0], 3'b000};
  //	assign DOUT = split ? {RAM_DIN[7:0], exdata} : (RAM_DIN >> {ADDR[1:0], 3'b000}); 
  assign RAM_DOUT = {DSWAP, DSWAP};
  assign RAM_MREQ = iread || RAM_RD || RAM_WR;
  assign RAM_ADDR = iread ? MIADDR : ADDR[20:2] + data_bound;
  assign RAM_WMASK = data_bound ? {3'b000, RAM_WR} : {2'b00, WORD & RAM_WR, RAM_WR} << ADDR[1:0];

  always @(*) begin
    RAM_RD = 0;
    RAM_WR = 0;
    CE186 = 0;
    sflush = 0;
    data_bound = 0;
    iread = 0;

    case (ADDR[1:0])
      2'b00: DOUT = RAM_DIN[15:0];
      2'b01: DOUT = RAM_DIN[23:8];
      2'b10: DOUT = RAM_DIN[31:16];
      2'b11: DOUT = {RAM_DIN[7:0], WORD ? exdata : RAM_DIN[31:24]};
    endcase

    case (STATE)
      0: begin  // no cpu activity on first state
        iread = qnofull;
        NEXTSTATE = 1;
      end
      1: begin
        NEXTSTATE = 1;
        if (FLUSH && IFETCH && !OLDSTATE) begin
          sflush = 1;
          iread  = 1;
        end else if ((FLUSH && IFETCH && (qsize > 5)) || (qsize > 11)) begin
          NEXTSTATE = 0;
          if (MREQ) begin
            if (WR) begin  // write
              RAM_WR = 1;
              if (split) NEXTSTATE = 3;
              else CE186 = 1;
            end else begin
              RAM_RD = 1;
              NEXTSTATE = split ? 2 : 3;
            end
          end else begin
            iread = qnofull;
            CE186 = 1;
          end
        end else iread = 1;  // else nextstate = 1
      end
      2: begin
        RAM_RD = 1;
        data_bound = 1;  // split memory access
        NEXTSTATE = 3;
      end
      3: begin
        RAM_WR = WR && MREQ;
        iread = !(WR && MREQ) && qnofull;
        data_bound = split;
        CE186 = 1;
        NEXTSTATE = 0;
      end
    endcase
  end

  always @(posedge CLK)
    if (CE) begin
      rdi <= iread;
      if (rdi) queue[rpos] <= RAM_DIN;
      if (iread) begin
        qsize  <= {newqsize[4:2] + 1, newqsize[1:0]};
        piaddr <= MIADDR + 1;
      end else begin
        qsize  <= newqsize;
        piaddr <= MIADDR;
      end
      if (CE186 && IFETCH) qpos <= nqpos;
      if (sflush) rpos <= 0;
      else if (rdi) rpos <= rpos + 1;
      OLDSTATE <= STATE[0];
      STATE <= NEXTSTATE;
      if (data_bound) exdata <= RAM_DIN[31:24];
    end

endmodule

files.origen_146848.v:
module origen_146848 (
    input wire clk,
    input wire rst_n,

    // Input events
    input wire InjectorArmFinishMovement_eI,
    input wire EmergencyStopChanged_eI,
    input wire CanisterPressureChanged_eI,
    input wire FillContentsAvailableChanged_eI,
    input wire LasersChanged_eI,
    input wire DoorOverride_eI,
    input wire VacuumTimerElapsed_eI,

    // Input variables
    input wire EmergencyStop_I,
    input wire [7:0] CanisterPressure_I,
    input wire [7:0] FillContentsAvailable_I,
    input wire DoorSiteLaser_I,
    input wire InjectSiteLaser_I,
    input wire RejectSiteLaser_I,
    input wire RejectBinLaser_I,
    input wire AcceptBinLaser_I,

    // Output events
    output reg DoorReleaseCanister_eO,
    output reg ConveyorChanged_eO,
    output reg InjectorPositionChanged_eO,
    output reg InjectorControlsChanged_eO,
    output reg FillContentsChanged_eO,
    output reg StartVacuumTimer_eO,
    output reg GoRejectArm_eO,
    output reg CanisterCountChanged_eO,
    output reg InjectDone_eO,

    // Output variables
    output reg [7:0] ConveyorSpeed_O,
    output reg [7:0] InjectorPosition_O,
    output reg InjectorContentsValveOpen_O,
    output reg InjectorVacuumRun_O,
    output reg InjectorPressurePumpRun_O,
    output reg [7:0] FillContents_O,
    output reg [15:0] CanisterCount_O
);

    // State machine states
    localparam IDLE = 3'd0;
    localparam INJECT = 3'd1;
    localparam VACUUM = 3'd2;
    localparam FILL = 3'd3;
    localparam REJECT = 3'd4;
    localparam ACCEPT = 3'd5;

    reg [2:0] current_state, next_state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            current_state <= IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    always @(*) begin
        next_state = current_state;

        case (current_state)
            IDLE: begin
                if (InjectSiteLaser_I && !EmergencyStop_I) next_state = INJECT;
            end
            INJECT: begin
                if (InjectorArmFinishMovement_eI) next_state = VACUUM;
            end
            VACUUM: begin
                if (VacuumTimerElapsed_eI) next_state = FILL;
            end
            FILL: begin
                if (CanisterPressureChanged_eI && CanisterPressure_I >= 8'hC8) next_state = ACCEPT;
                else if (CanisterPressureChanged_eI && CanisterPressure_I < 8'hC8) next_state = REJECT;
            end
            REJECT: begin
                if (RejectBinLaser_I) next_state = IDLE;
            end
            ACCEPT: begin
                if (AcceptBinLaser_I) next_state = IDLE;
            end
        endcase

        if (EmergencyStop_I) next_state = IDLE;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            DoorReleaseCanister_eO <= 0;
            ConveyorChanged_eO <= 0;
            InjectorPositionChanged_eO <= 0;
            InjectorControlsChanged_eO <= 0;
            FillContentsChanged_eO <= 0;
            StartVacuumTimer_eO <= 0;
            GoRejectArm_eO <= 0;
            CanisterCountChanged_eO <= 0;
            InjectDone_eO <= 0;
            ConveyorSpeed_O <= 0;
            InjectorPosition_O <= 0;
            InjectorContentsValveOpen_O <= 0;
            InjectorVacuumRun_O <= 0;
            InjectorPressurePumpRun_O <= 0;
            FillContents_O <= 0;
            CanisterCount_O <= 0;
        end else begin
            case (next_state)
                IDLE: begin
                    ConveyorChanged_eO <= 1;
                    ConveyorSpeed_O <= 8'h64; // Set conveyor speed to 100
                end
                INJECT: begin
                    InjectorPositionChanged_eO <= 1;
                    InjectorPosition_O <= 8'hFF; // Move injector to full extend
                end
                VACUUM: begin
                    StartVacuumTimer_eO <= 1;
                    InjectorControlsChanged_eO <= 1;
                    InjectorVacuumRun_O <= 1;
                end
                FILL: begin
                    InjectorControlsChanged_eO <= 1;
                    InjectorVacuumRun_O <= 0;
                    InjectorContentsValveOpen_O <= 1;
                    FillContentsChanged_eO <= 1;
                    FillContents_O <= FillContentsAvailable_I;
                end
                REJECT: begin
                    GoRejectArm_eO <= 1;
                    CanisterCountChanged_eO <= 1;
                    CanisterCount_O <= CanisterCount_O + 1;
                end
                ACCEPT: begin
                    InjectDone_eO <= 1;
                    CanisterCountChanged_eO <= 1;
                    CanisterCount_O <= CanisterCount_O + 1;
                end
            endcase

            if (EmergencyStop_I) begin
                DoorReleaseCanister_eO <= 1;
                ConveyorChanged_eO <= 1;
