module origen_138055 (
    input wire clk,
    input wire rst_n,
    input wire [31:0] data_in,
    output reg [31:0] filtered_data
);

// Parameters
parameter CUTOFF_FREQ = 1000; // Hz
parameter SAMPLING_FREQ = 44100; // Hz (typical audio sampling rate)
parameter FILTER_ORDER = 8;

// Internal signals
wire [31:0] shifted_data;
wire edge_detected;
reg [31:0] delay_line [FILTER_ORDER-1:0];
reg [31:0] filter_coeff [FILTER_ORDER-1:0];

// Instantiate barrel shifter
barrel_shifter bs (
    .data_in(data_in),
    .shift_amount(4'd8), // Shift by 8 bits (divide by 256)
    .direction(1'b1), // Right shift
    .data_out(shifted_data)
);

// Instantiate edge detector
edge_detector ed (
    .clk(clk),
    .rst_n(rst_n),
    .signal_in(data_in[31]),
    .edge_detected(edge_detected)
);

// Calculate filter coefficients (simplified low-pass filter)
initial begin
    integer i;
    real pi = 3.14159265359;
    real fc = real'(CUTOFF_FREQ) / real'(SAMPLING_FREQ);
    for (i = 0; i < FILTER_ORDER; i = i + 1) begin
        filter_coeff[i] = $rtoi(32767.0 * $sin(2.0 * pi * fc * real'(i)) / (pi * real'(i)));
    end
end

// Implement digital filter
always @(posedge clk or negedge rst_n) begin
    integer i;
    if (!rst_n) begin
        filtered_data <= 32'b0;
        for (i = 0; i < FILTER_ORDER; i = i + 1) begin
            delay_line[i] <= 32'b0;
        end
    end else begin
        // Shift delay line
        for (i = FILTER_ORDER-1; i > 0; i = i - 1) begin
            delay_line[i] <= delay_line[i-1];
        end
        delay_line[0] <= shifted_data;

        // Apply filter
        filtered_data <= 32'b0;
        for (i = 0; i < FILTER_ORDER; i = i + 1) begin
            filtered_data <= filtered_data + (delay_line[i] * filter_coeff[i]);
        end

        // Apply edge detection
        if (edge_detected) begin
            filtered_data <= 32'b0; // Reset output on edge detection
        end
    end
end

endmodule

module barrel_shifter (
    input wire [31:0] data_in,
    input wire [3:0] shift_amount,
    input wire direction,
    output wire [31:0] data_out
);
    assign data_out = direction ? (data_in >> shift_amount) : (data_in << shift_amount);
endmodule

module edge_detector (
    input wire clk,
    input wire rst_n,
    input wire signal_in,
    output reg edge_detected
);
    reg signal_prev;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            signal_prev <= 1'b0;
            edge_detected <= 1'b0;
        end else begin
            signal_prev <= signal_in;
            edge_detected <= signal_in & ~signal_prev;
        end
    end
endmodule

