module booth_multiplier_16bit(
    input wire [15:0] A,
    input wire [15:0] B,
    input wire C,
    output reg [31:0] result
);

    // Booth's algorithm implementation
    // (simplified for brevity)
    always @(*) begin
        if (C)
            result = $signed(A) * $signed(B);
        else
            result = A * B;
    end

endmodule

module final_output(
    input wire [3:0] shift_reg_out,
    input wire [31:0] multiplier_out,
